#include <stdio.h>
#include <string.h>
#include <ctype.h>

int isPalindrome(char* text) {
    int len = strlen(text);
    int left = 0, right = len - 1;

    while (left < right) {
        // Bosluklari atla
        while (left < right && text[left] == ' ') left++;
        while (left < right && text[right] == ' ') right--;

        if (tolower(text[left]) != tolower(text[right])) {
            return 0;
        }
        left++;
        right--;
    }
    return 1;
}

int isNumberPalindrome(int number) {
    char text[20];
    sprintf(text, "%d", number);
    return isPalindrome(text);
}

int main() {
    char* words[] = {"kayak", "araba", "anna", "elma", "a man a plan a canal panama"};
    int wordCount = 5;

    printf("Kelime testleri:\n");
    for (int i = 0; i < wordCount; i++) {
        printf("'%s' palindrome mu: %s\n", words[i], isPalindrome(words[i]) ? "Evet" : "Hayir");
    }

    printf("\nSayi testleri:\n");
    int numbers[] = {12321, 12345, 1001, 5};
    for (int i = 0; i < 4; i++) {
        printf("%d palindrome mu: %s\n", numbers[i], isNumberPalindrome(numbers[i]) ? "Evet" : "Hayir");
    }

    return 0;
}
